module top_module(
    INV_Q      ,
    CLK_N  ,
    D      ,
    SCD    ,
    SCE    ,
    RESET_B
);output INV_Q      ;
    input  CLK_N  ;
    input  D      ;
    input  SCD    ;
    input  SCE    ;
    input  RESET_B;

    // Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

    reg INV_Q;

    always @(negedge CLK_N) begin
        if(RESET_B == 1'b0) begin
            INV_Q <= 1'b0;
        end else if(SCD == 1'b1) begin
            INV_Q <= 1'b0;
        end else if(SCE == 1'b0) begin
            INV_Q <= INV_Q;
        end else begin
            INV_Q <= D;
        end
    end

endmodule
